class WidgetLoadTest : Simulation() { val httpProtocol = http.baseUrl("http://localhost:8080") .acceptHeader("application/json")
val scn = scenario("Widget CRUD Load Test") .exec(http("Create Widget") .post("/api/v1/widgets") .body(StringBody("""{"name":"Load Test Widget"}""")) .check(status().is(201)))
setUp(scn.inject( atOnceUsers(10), rampUsers(100).during(Duration.ofSeconds(30)) )).assertions( global().responseTime().p95().lt(200), global().successfulRequests().percent().gt(99.0) ) }
